mapper.update:
UPDATE t_car_cost_oil_card_receive
SET waybill_id = #{waybillId}
WHERE oil_card_receive_id = #{oilCardReceiveId}

mapper.select:
SELECT ROUND(IFNULL(SUM(Amount), 0), 4)
FROM t_car_cost_oil_card_receive
WHERE waybill_id = #{waybillId} AND oil_card_id = #{oilCardId} AND audit_status = #{auditStatus}

SELECT
ccocr.vehicle_id,
SUM(ccocr.amount) amount
FROM
t_car_cost_oil_card_receive ccocr
LEFT JOIN t_waybill w ON w.waybill_id = ccocr.waybill_id
where DATE_FORMAT(w.create_time, '%Y-%m-%d') >= #{queryForm.startTime}
AND DATE_FORMAT(w.create_time, '%Y-%m-%d') <= #{queryForm.endTime}
and ccocr.enterprise_id = #{queryForm.enterpriseId}
and ccocr.vehicle_id in

    #{item}

GROUP BY ccocr.vehicle_id

SELECT ccocr.*, cct.tabulation_id, cct.module_id, cct.module_type, w.waybill_number, w.container_number, v.vehicle_number, d.driver_name, ccc.cost_type, ccc.category_name FROM t_car_cost_tabulation cct LEFT JOIN t_waybill w ON cct.waybill_id = w.waybill_id LEFT JOIN t_vehicle v ON cct.vehicle_id = v.vehicle_id LEFT JOIN t_driver d ON cct.driver_id = d.driver_id LEFT JOIN t_car_cost_category ccc ON cct.category_id = ccc.category_id LEFT JOIN t_car_cost_oil_card_receive ccocr ON cct.module_id = ccocr.oil_card_receive_id
cct.tabulation_id IN
#{item}
